long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    // Initialize a 2D DP array to store the minimum cost to reach each cell
    vector<vector<long long>> dp(m, vector<long long>(n, LONG_MAX));

    // Starting cell (0, 0) has an initial cost of (0+1)*(0+1) = 1
    dp[0][0] = 1;

    // Directions: right (0, 1), down (1, 0)
    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};

    // Use a priority queue to perform Dijkstra's algorithm
    priority_queue<pair<long long, pair<int, int>>, vector<pair<long long, pair<int, int>>>, greater<>> pq;
    pq.push({dp[0][0], {0, 0}});

    while (!pq.empty()) {
        long long currentCost = pq.top().first;
        int i = pq.top().second.first;
        int j = pq.top().second.second;
        pq.pop();

        // If we have already found a better path to this cell, skip it
        if (currentCost > dp[i][j]) {
            continue;
        }

        // If we have reached the destination, return the cost
        if (i == m - 1 && j == n - 1) {
            return currentCost;
        }

        // Move to the next cell (right or down) in the odd second
        for (auto& dir : directions) {
            int ni = i + dir.first;
            int nj = j + dir.second;

            // Check if the new cell is within bounds
            if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                long long newCost = currentCost + (ni + 1) * (nj + 1);
                if (newCost < dp[ni][nj]) {
                    dp[ni][nj] = newCost;
                    pq.push({newCost, {ni, nj}});
                }
            }
        }

        // Wait in the current cell in the even second
        if (i > 0 || j > 0) {  // Only wait if we are not at the starting cell
            long long newCost = currentCost + waitCost[i][j];
            if (newCost < dp[i][j]) {
                dp[i][j] = newCost;
                pq.push({newCost, {i, j}});
            }
        }
    }

    // If we cannot reach the destination, return -1 (though the problem states it is always possible)
    return -1;
}

